SELECT code, name, type, category
FROM "Account"
WHERE code LIKE '111%' OR code LIKE '112%' OR code LIKE '113%' OR code LIKE '114%' OR code LIKE '115%' OR code LIKE '116%' OR code LIKE '117%' OR code LIKE '118%' OR code LIKE '119%' OR code LIKE '120%' OR code LIKE '121%' OR code LIKE '122%' OR code LIKE '123%' OR code LIKE '124%' OR code LIKE '125%' OR code LIKE '126%' OR code LIKE '127%' OR code LIKE '128%' OR code LIKE '129%' OR code LIKE '130%' OR code LIKE '131%' OR code LIKE '132%' OR code LIKE '133%' OR code LIKE '134%' OR code LIKE '135%' OR code LIKE '136%' OR code LIKE '137%' OR code LIKE '138%' OR code LIKE '139%' OR code LIKE '210%' OR code LIKE '211%' OR code LIKE '212%' OR code LIKE '213%' OR code LIKE '214%' OR code LIKE '215%' OR code LIKE '216%' OR code LIKE '217%' OR code LIKE '218%' OR code LIKE '219%' OR code LIKE '220%' OR code LIKE '221%' OR code LIKE '222%' OR code LIKE '223%' OR code LIKE '224%' OR code LIKE '225%' OR code LIKE '226%' OR code LIKE '227%' OR code LIKE '228%' OR code LIKE '229%' OR code LIKE '230%' OR code LIKE '231%' OR code LIKE '232%' OR code LIKE '233%' OR code LIKE '234%' OR code LIKE '235%' OR code LIKE '236%' OR code LIKE '237%' OR code LIKE '238%' OR code LIKE '239%' OR code LIKE '300%' OR code LIKE '311%' OR code LIKE '312%' OR code LIKE '313%' OR code LIKE '314%' OR code LIKE '315%' OR code LIKE '316%' OR code LIKE '317%' OR code LIKE '318%' OR code LIKE '319%'
